code = """import json
from collections import defaultdict

# Load case data from previous result
cases_result = var_functions.query_db:0
order_items_result = var_functions.query_db:2

# Extract order item IDs for SecureAnalytics Pro
secure_order_item_ids = set()
for item in order_items_result:
    order_item_id = item['Id']
    # Handle leading # corruption
    if order_item_id.startswith('#'):
        order_item_id = order_item_id[1:]
    secure_order_item_ids.add(order_item_id)

# Filter cases to only include those with SecureAnalytics Pro order items
secure_cases = []
for case in cases_result:
    case_order_item_id = case['orderitemid__c']
    # Handle potential corruption
    if case_order_item_id and case_order_item_id.startswith('#'):
        case_order_item_id = case_order_item_id[1:]
    
    if case_order_item_id in secure_order_item_ids:
        secure_cases.append(case)

# Group cases by month
monthly_counts = defaultdict(int)
month_names = {
    '06': 'June', '07': 'July', '08': 'August', '09': 'September',
    '10': 'October', '11': 'November', '12': 'December',
    '01': 'January', '02': 'February', '03': 'March', '04': 'April'
}

for case in secure_cases:
    created_date = case['createddate']
    # Extract month from date format
    date_part = created_date.split('T')[0]
    year_month = date_part.split('-')[1]  # MM format
    
    # Only include past 10 months from April 2021 (June 2020 to April 2021)
    if date_part >= '2020-06-01' and date_part <= '2021-04-10':
        if year_month in month_names:
            monthly_counts[year_month] += 1

# Prepare output
output = []
for month_num, name in month_names.items():
    if month_num in monthly_counts:
        output.append({
            'month_number': month_num,
            'month_name': name,
            'case_count': monthly_counts[month_num]
        })

# Sort by month number
output.sort(key=lambda x: x['month_number'])

# Also return the full data for analysis
analysis_data = {
    'monthly_counts': output,
    'filtered_cases': secure_cases
}

print('__RESULT__:')
print(json.dumps(analysis_data, indent=2))"""

